	@Test
	void initWrapsQueryStorageInitializationFailures(@TempDir Path tempDir) throws Exception {
		String key = "org.eclipse.rdf4j.appdata.basedir";
		String previous = System.getProperty(key);
		Path workbenchDir = tempDir.resolve("Workbench");
		Files.createDirectories(workbenchDir);
		Files.writeString(workbenchDir.resolve("queries"), "not-a-directory");

		QueryServlet servlet = new QueryServlet();
		servlet.setRepositoryManager(mock(RepositoryManager.class));

		try {
			System.setProperty(key, tempDir.toString());

			assertThatThrownBy(() -> servlet.init(
					TestServletConfig.withParams("query", "transformations", "/transform", "cookie-max-age", "60")))
					.isInstanceOf(ServletException.class)
					.hasCauseInstanceOf(RepositoryException.class);
		} finally {
			if (previous == null) {
				System.clearProperty(key);
			} else {
				System.setProperty(key, previous);
			}
		}
	}

